// 定义组件容器
let container = null;
let messageBrige = null;

function MessageContainer({ callabck }) {
  const bridge = useRef({
    add: (opts) => {
      opts.key = `renderKey_${bridge.current.count}`;
      bridge.current.map[opts.key] = opts;
      bridge.current.reset();
    },
    remove: (key) => {
      if (bridge.current.map[key]) {
        delete bridge.current.map[key];
        bridge.current.reset();
      }
    },
    list: [],
    map: {},
    count: 0,
    reset: () => {
      const ls = [];
      Object.keys(bridge.current.map).forEach((k) => {
        ls.push(bridge.current.map[k]);
      });
      bridge.current.count += 1;
      setList(ls);
    },
  });

  const [list, setList] = useState([]);
  // 全局委托
  useEffect(() => {
    messageBrige = bridge.current;
    callabck();
  }, []);
  console.log(45, list);
  return list.map((item) => <MessageUnit key={item.key} bridge={item.bridge} ckey={item.key} {...item.props} />);
}

const MessageUnit = memo(({
  bridge, // 外层接收方法容器
  className = '', // 额外类名
  style = {}, // 样式
  duration = 2, // 展示时长
  onClose, // 消失回调
  ckey,
  ...props
}) => {
  const elmRef = useRef(null);
  const timerRef = useRef(null);
  const dataRef = useRef({
    status: '',
  });
  dataRef.current.className = className;

  console.log(444, props)
  return (
    <div ref={elmRef}>
      {props.icon && (
        <div className="eui-message-icon">{props.icon}</div>
      )}
      <div className="eui-message-container-content">{props.content}</div>
    </div>
  );
});

// 检查传入的值，格式化参数，补充type
const resetProps = (props) => {
  let rs = props;
  if (getType(rs) !== 'object') {
    rs = { content: props, type: 'info' };
  }
  if (types.indexOf(rs.type) === -1) {
    rs.type = 'info';
  }
  if (rs.type === 'loading') {
    rs.duration = 0;
  }
  return rs
}

// 判断并创建容器
const buildContainer = (cb) => {
  if (!container) {
    container = document.createElement('div');
    container.setAttribute('class', 'eui-message');
    document.body.appendChild(container);
    const root = createRoot(container);
    container = <MessageContainer callabck={cb} />;
    root.render(container);
  } else {
    cb();
  }
};

const Toast = (props) => {
  console.log(4566, resetProps(props));
  // 查看是否存在容器载体，存放消息dom
  buildContainer(() => {
    messageBrige.add({ props: resetProps(props) });
  });
};

// 绑定扩展方法
const types = ['info', 'warning', 'fail', 'success', 'loading'];
types.forEach(type => {
  Toast[type] = (props) => {
    Toast({ ...resetProps(props), type })
  }
});

export default Toast;
