import React, { memo, useState, useEffect, useRef, useCallback, useMemo } from 'react';
import styles from './loading.module.css';

const Loading = memo(({
  visible,
  fixed,
  className = '',
  content,
  title,
}) => {
  const dataRef = useRef({ timer: 0 });
  const [fadeIn, setFadeIn] = useState(false);
  const [show, setShow] = useState(false);

  useEffect(() => {
    dataRef.current.destroy = false;
    return () => {
      dataRef.current.destroy = true;
    };
  }, [])

  useEffect(() => {
    clearTimeout(dataRef.current.timer);
    if (visible) {
      setShow(true);
      setFadeIn(true);
    } else if (dataRef.current.init) {
      setFadeIn(false);
      dataRef.current.timer = setTimeout(() => {
        if (!dataRef.current.destroy) {
          setShow(false);
        }
      }, 200);
    } else {
      dataRef.current.init = true;
      setShow(false);
      setFadeIn(false);
    }
  }, [visible]);
  
  const classList = useMemo(() => {
    const cs = [];
    if (fixed) {
      cs.push(styles['loading-fixed']);
    };
    if (fadeIn) {
      cs.push(styles['loading-fadein']);
    }
    if (show) {
      cs.push(styles['loading-show']);
    }
    return cs.join(' ');
  }, [fixed, show, fadeIn]);
  return (
    <div className={`${styles['loading']} ${classList} ${className}`}>
      <div className={`loading-icon ${styles['loading-icon']}`}>
        <div className={styles['loading-icon-row']}>
          <div className={`${styles['loading-icon-dot']} ${styles['loading-icon-dot-tl']}`}></div>
          <div className={`${styles['loading-icon-dot']} ${styles['loading-icon-dot-tr']}`}></div>
        </div>
        <div className={styles['loading-icon-row']}>
          <div className={`${styles['loading-icon-dot']} ${styles['loading-icon-dot-bl']}`}></div>
          <div className={`${styles['loading-icon-dot']} ${styles['loading-icon-dot-br']}`}></div>
        </div>
      </div>
      {title && <div className={styles['loading-title']}>{title}</div>}
      {content && <div className={`${styles['loading-content']} ${!title ? styles['loading-content-notitle'] : ''}`}>{content}</div>}
    </div>
  )
});

export default Loading;